🧠 Variante complète qui combine les deux autres
📦 Extrait ingrédient principal + catégories + pairings

javascriptCopierModifierfunction extractAllFoodpairingData() {
    var result = {
        mainIngredient: {},
        categories: {},
        pairings: []
    };

    var main = document.querySelector('.ingredient-header');
    if (main) {
        var img = main.querySelector('img');
        result.mainIngredient = {
            name: main.querySelector('.title')?.innerText || "",
            extra: main.querySelector('.subtitle')?.innerText || "",
            img_url: img ? img.src : ""
        };
    }

    var cat = document.querySelector('.categories .category');
    var subcat = document.querySelector('.categories .subcategory');
    result.categories = {
        category: {
            name: cat?.innerText || ""
        },
        subcategory: {
            name: subcat?.innerText || ""
        }
    };

    var pairings = document.querySelectorAll('.pairing-item, .ingredient-box');
    pairings.forEach(function(item) {
        var name = item.querySelector('.name')?.innerText || "";
        var extra = item.querySelector('.extra')?.innerText || "";
        var percent = item.querySelector('.percent')?.innerText || "";
        var img = item.querySelector('img')?.src || "";
        if (name !== "") {
            result.pairings.push({
                name: name,
                extra: extra,
                percentage: percent.replace('%', '').trim(),
                img_url: img
            });
        }
    });

    return result;
}


