var RecipeInfoPanel =
{
    load: function () {
        $.get('/Partial/RecipeInfoPanel', { 'recipeId': $('#recipeId').val() }, function (html) {
            $('#recipeInfoPanelContent').html(html);
        },
		'html');
    },

    setHtml: function (html) {
        $('#recipeInfoPanelContent').html(html);
    },

    editSingleLineField: function (elem, callback) {
        elem.onclick = null;
        var text = $(elem).html();
        var input = $('<input type="text" value="' + text + '" />');
        $(elem).empty().append(input);
        input.focus();
        input.on('keypress', function (e) {
            if (e.which == 13) {
                input.off('keypress blur');
                callback(elem, input);
            }
        });
        input.on('blur', function(e) {
            input.off('keypress blur');
            callback(elem, input);
        });
    },

    editTitleCanvas: function (elem) {
        RecipeInfoPanel.editSingleLineField(elem, RecipeInfoPanel.saveTitleCanvas);
    },

    saveTitleCanvas: function (elem, input) {
        $.get('/Partial/SetRecipeTitle', { 'recipeId': $('#recipeId').val(), 'step': $('#step').val(), 'title': input.val() }, function () { $(elem).html(input.val()); elem.onclick = function () { RecipeInfoPanel.editTitleCanvas(elem); }; }, 'html');
        RecipeInfoPanel.showSaveIndicator();
    },

    editTitle: function (elem) {
        RecipeInfoPanel.editSingleLineField(elem, RecipeInfoPanel.saveTitle);
    },

    saveTitle: function (elem, input) {
        $.get('/Partial/SetRecipeTitle', { 'recipeId': $('#recipeId').val(), 'step': $('#step').val(), 'title': input.val() }, RecipeInfoPanel.setHtml, 'html');
        RecipeInfoPanel.showSaveIndicator();
    },

    editNotes: function (elem) {
        elem.onclick = null;
        var text = $(elem).text();
        var input = $('<textarea>' + text + '</textarea>');
        var btn = $('<span class="btn sml saveButton">save</span><div class="emptyClearing"></div>');
        $(elem).empty().append(input).append(btn);
        input.focus();
        btn.on('click', function () { RecipeInfoPanel.saveNotes(input); });
        input.on('blur', function () { RecipeInfoPanel.saveNotes(input); });
    },

    saveNotes: function (input) {
        $.post('/Partial/SetRecipeNotes', { 'recipeId': $('#recipeId').val(), 'step': $('#step').val(), 'notes': input.val() }, RecipeInfoPanel.setHtml, 'html');
        RecipeInfoPanel.showSaveIndicator();
    },

    addIngredient: function (elem) {
        $(elem).empty();
        RecipeInfoPanel.editSingleLineField(elem, RecipeInfoPanel.saveIngredient);
    },

    savePairing: function (elem) {

        $.ajax("/FromScratch/SavePairing",
        {
            'type': 'POST',
            'data': JSON.stringify({
                'recipeId': $('#recipeId').val()
            }),
            'success': function (html) {
                $("#btnSavePairing").hide();
                $(".actionButtons div.message").show();
            },
            'error': function (html) {
                $(".actionButtons div.error").show();
            },
            'dataType': "html",
            'contentType': 'application/json'
        });


    },

    saveIngredient: function (elem, input) {
        if (input.val() === '') {
            RecipeInfoPanel.load();
        } else {
            $.get('/Partial/SaveFreeIngredient', { 'recipeId': $('#recipeId').val(), 'step': $('#step').val(), 'title': input.val() }, RecipeInfoPanel.setHtml, 'html');
            RecipeInfoPanel.showSaveIndicator();
        }
    },

    removeIngredient: function (elem, ingredientId) {
        elem.onclick = null;
        var ingredientBox = $(elem).parents('.ingredientBox:first');
        $.get('/Partial/RemoveFreeIngredient', { 'recipeId': $('#recipeId').val(), 'step': $('#step').val(), 'ingredientId': ingredientId }, RecipeInfoPanel.setHtml, 'html');
    },

    editAmountDone: function (elem, ingredientId) {
        var amountEditBox = $(elem).parents('.amountEditBox:first');
        var ingredientBox = $(elem).parents('.ingredientBox:first');
        var amount = amountEditBox.find('.amount').val();
        var patt = /^[0-9]+$/;
        if (amount != '' && !patt.test(amount)) {
            alert('Please enter a valid number');
            amountEditBox.find('.amount').focus();
            return;
        }
        elem.onclick = null;
        $.get('/Partial/SaveIngredientAmount', { 'recipeId': $('#recipeId').val(), 'step': $('#step').val(), 'ingredientId': ingredientId, 'amount': (amount ? amount : 0), 'unitId': amountEditBox.find('.unit').val() }, RecipeInfoPanel.setHtml, 'html');
        RecipeInfoPanel.showSaveIndicator();
    },

    editAmount: function (elem, ingredientId) {
        elem.onclick = null;
        $.get('/Partial/IngredientAmount', { 'ingredientId': ingredientId }, function (html) {
            var newElem = $(html);
            newElem.on('click', function(e) {
                e.stopPropagation();
            });
            $(elem).html(newElem);
            newElem.find('.amount').focus();
        }, 'html');
    },

    editIngredientTitle: function (elem, ingredientId) {
        elem.onclick = null;
        var text = $(elem).html();
        var input = $('<input type="text" value="' + text + '" />');
        $(elem).empty().append(input);
        input.focus();
        input.on('keypress', function (e) {
            if (e.which == 13) RecipeInfoPanel.saveIngredientTitle(elem, ingredientId, input);
        });
    },

    saveIngredientTitle: function (elem, ingredientId, input) {
        var ingredientBox = $(elem).parents('.ingredientBox:first');
        $.get('/Partial/SaveIngredientTitle', { 'recipeId': $('#recipeId').val(), 'step': $('#step').val(), 'ingredientId': ingredientId, 'title': input.val() }, RecipeInfoPanel.setHtml, 'html');
        RecipeInfoPanel.showSaveIndicator();
    },

    showSaveIndicator: function () {
        var positievandesaveindicator = $("header").height() + $(".upgrade").height();
        $('#saveIndicator').stop().animate({
            top: positievandesaveindicator
        }, 500)
		.delay(2000)
		.animate({
		    top: '0px'
		}, 500);
    }

};

