    console.log("🔍 Extension GlobalExtension en cours d'exécution...");

    const wait = (ms) => new Promise((resolve) => setTimeout(resolve, ms));

    const getSelectOptions = (selector) => {
        return Array.from(document.querySelectorAll(`${selector} option`))
            .map(opt => ({ value: opt.value, text: opt.textContent.trim() }))
            .filter(opt => opt.value !== "");
    };

    const clickLoadMoreUntilEnd = async () => {
        let attempts = 0;
        while (document.querySelector("#loadMoreButton") && attempts < 20) {
            console.log("⏳ Click bouton #loadMoreButton");
            document.querySelector("#loadMoreButton").click();
            await wait(1000);
            attempts++;
        }
    };

    const getIngredients = () => {
        return Array.from(document.querySelectorAll("#productList .ingredientBox")).map(elem => {
            const id = elem.getAttribute("data-id") || "";
            const name = elem.querySelector(".ingredientTitle")?.textContent.trim() || "";
            return { id, name };
        });
    };

    const selectAndTrigger = async (selectId, value) => {
        const select = document.querySelector(`#${selectId}`);
        if (!select) return;
        select.value = value;
        select.dispatchEvent(new Event("change", { bubbles: true }));
        await wait(2000); // Attente du rechargement des résultats
    };

    const categories = getSelectOptions("#advFilterCat");
    const subcategories = getSelectOptions("#advFilterSubCat");
    const cuisines = getSelectOptions("#advFilterCuisine");
    const seasonality = getSelectOptions("#advFilterSeasonality");
    const flavours = getSelectOptions("#advFilterFlavour");

    const extractedData = [];

    for (let cat of categories.slice(0, 3)) { // <-- Limite temporaire pour test
        await selectAndTrigger("advFilterCat", cat.value);
        await wait(1500);

        for (let sub of subcategories.slice(0, 2)) {
            await selectAndTrigger("advFilterSubCat", sub.value);

            for (let cuisine of cuisines.slice(0, 2)) {
                await selectAndTrigger("advFilterCuisine", cuisine.value);

                for (let season of seasonality.slice(0, 2)) {
                    await selectAndTrigger("advFilterSeasonality", season.value);

                    for (let flavour of flavours.slice(0, 2)) {
                        await selectAndTrigger("advFilterFlavour", flavour.value);

                        await clickLoadMoreUntilEnd();

                        const ingredients = getIngredients();
                        console.log(`✅ ${ingredients.length} ingrédient(s) trouvés pour :`, {
                            cat: cat.text, sub: sub.text, cuisine: cuisine.text, season: season.text, flavour: flavour.text
                        });

                        extractedData.push({
                            category: cat,
                            subcategory: sub,
                            cuisine: cuisine,
                            season: season,
                            flavour: flavour,
                            ingredients
                        });
                    }
                }
            }
        }
    }

    console.log("📦 Données extraites :", extractedData);

    // 📨 Envoi à l'API locale
    try {
        const response = await fetch("http://127.0.0.1:5001/api/ingredients", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ data: extractedData })
        });

        if (response.ok) {
            console.log("✅ Données envoyées à l'API avec succès !");
        } else {
            console.error("❌ Erreur API :", response.status, await response.text());
        }
    } catch (err) {
        console.error("❌ Erreur fetch API :", err);
    }
})();


